#include <bits/stdc++.h>
using namespace std;
string a,b;
int la,lb,dp[2003][2003];
int main(){
	cin>>a>>b;
	la=a.size(),lb=b.size(),a=" "+a,b=" "+b;
	for(int i=0;i<=max(la,lb);i++)
		dp[i][0]=dp[0][i]=i;
	for(int i=1;i<=la;i++)
		for(int j=1;j<=lb;j++){
			if(i==j && i==1)
				dp[i][j]=(a[i]!=b[j]);
			else if(a[i]==b[j])
				dp[i][j]=min(min(dp[i-1][j]+1,dp[i][j-1]+1),dp[i-1][j-1]);
			else
				dp[i][j]=min(min(dp[i-1][j]+1,dp[i][j-1]+1),dp[i-1][j-1]+1);
		}
	printf("%d",dp[la][lb]);
	return 0;
}
